import React from 'react';/** * A component for displaying an individual todo item. * @param {object} props - The component props. * @param {object} props.todo - The todo object containing id, text, and completed status. * @param {function} props.toggleComplete - Function to toggle the todo's completion status. * @param {function} props.deleteTodo - Function to delete the todo item. */function TodoItem({ todo, toggleComplete, deleteTodo }) {  return (    <div className={`todo-item ${todo.completed ? 'completed' : ''}`}>      <input        type="checkbox"        checked={todo.completed}        onChange={() => toggleComplete(todo.id)}        aria-label={`Mark ${todo.text} as ${todo.completed ? 'incomplete' : 'complete'}`}      />      <span className="todo-text">{todo.text}</span>      <button        onClick={() => deleteTodo(todo.id)}        className="delete-button"        aria-label={`Delete ${todo.text}`}      >        Delete      </button>    </div>  );};export default TodoItem;